def get_sigma(
    structure: Atoms,
    cutoff: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/DimensionlessRatio",
        },
    ] = 4,
    sigma_start: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ] = 2,
    d_sigma: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ] = 1,
    epsilon: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ] = 1,
    n_cycle: Annotated[
        int,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/Dimensionless",
        },
    ] = 20,
) -> tuple[
    Annotated[
        float,
        {
            "label": "sigma",
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
    Annotated[
        NDArray[np.float64],
        {
            "label": "p_hist",
            "unit": "https://qudt.org/vocab/unit/EV_PER_ANGSTROM3",
            "quantity": "https://qudt.org/vocab/quantitykind/Pressure",
        },
    ],
]:
    """
    Optimizes the LJ sigma parameter to achieve zero pressure.

    Args:
        structure: ASE Atoms object.
        cutoff: Cutoff radius multiplier.
        sigma_start: Initial sigma value.
        d_sigma: Initial step size for sigma adjustment.
        epsilon: LJ epsilon parameter.
        n_cycle: Number of optimization cycles.

    Returns:
        tuple: Optimized sigma value and pressure history.
    """
    sigma = sigma_start
    p_hist = []
    for _ in range(20):
        neigh = get_neighbors(
            structure, num_neighbors=None, cutoff_radius=cutoff * sigma
        )
        p = get_lj_pressure(
            neigh.distances, neigh.vecs, sigma, epsilon, structure.get_volume()
        )[0, 0]
        p_hist.append([sigma, p])
        if p < 0:
            sigma += d_sigma
        else:
            sigma -= d_sigma
        d_sigma *= 0.5
    p_hist = np.array(p_hist)
    return sigma, p_hist

def get_epsilon(
    structure: Atoms,
    sigma: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
    ureg: UnitRegistry,
    bulk_modulus_dict: dict[
        str,
        Annotated[
            float,
            {
                "unit": "https://qudt.org/vocab/unit/GigaPA",
                "quantity": "https://qudt.org/vocab/quantitykind/BulkModulus",
            },
        ],
    ],
    epsilon_start: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ] = 0.6,
    d_epsilon: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ] = 0.5,
    n_cycle: Annotated[
        int,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/Dimensionless",
        },
    ] = 20,
    cutoff: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/DimensionlessRatio",
        },
    ] = 4,
    factor: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/DimensionlessRatio",
        },
    ] = 0.99,
) -> tuple[
    Annotated[
        float,
        {
            "label": "epsilon",
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ],
    Annotated[
        NDArray[np.float64],
        {
            "label": "e_hist",
            "unit": "https://qudt.org/vocab/unit/GigaPA",
            "quantity": "https://qudt.org/vocab/quantitykind/BulkModulus",
        },
    ],
]:
    """
    Optimizes the LJ epsilon parameter to match reference bulk modulus.

    Args:
        structure: ASE Atoms object.
        sigma: LJ sigma parameter.
        ureg: Pint UnitRegistry for unit conversion.
        bulk_modulus_dict: Dictionary of reference bulk moduli.
        epsilon_start: Initial epsilon value.
        d_epsilon: Initial step size for epsilon adjustment.
        n_cycle: Number of optimization cycles.
        cutoff: Cutoff radius multiplier.
        factor: Compression factor for bulk modulus calculation.

    Returns:
        tuple: Optimized epsilon value and bulk modulus history.
    """
    ref_bulk_modulus = bulk_modulus_dict[structure.get_chemical_symbols()[0]]
    epsilon = epsilon_start
    e_hist = []
    for n in range(n_cycle):
        B = (
            (
                get_bulk_modulus(structure, sigma, epsilon)
                * ureg.electron_volt
                / ureg.angstrom**3
            )
            .to("gigapascal")
            .magnitude
        )
        e_hist.append([epsilon, B])
        if B > ref_bulk_modulus:
            epsilon -= d_epsilon
        else:
            epsilon += d_epsilon
        d_epsilon *= 0.5
    return epsilon, np.array(e_hist)

def get_cutoff_radius(
    sigma: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
    mul: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/DIMENSIONLESS",
            "quantity": "https://qudt.org/vocab/quantitykind/DimensionlessRatio",
        },
    ] = 4,
) -> Annotated[
    float,
    {
        "label": "cutoff_radius",
        "unit": "https://qudt.org/vocab/unit/ANGSTROM",
        "quantity": "https://qudt.org/vocab/quantitykind/Length",
    },
]:
    """
    Calculates cutoff radius for neighbor calculations.

    Args:
        sigma: LJ sigma parameter.
        mul: Multiplier for cutoff radius.

    Returns:
        float: Cutoff radius.
    """
    cutoff_radius = sigma * mul
    return cutoff_radius

def get_bulk_energy(
    bulk: Atoms,
    sigma: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
    epsilon: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ],
    cutoff_radius: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
) -> Annotated[
    float,
    {
        "label": "bulk_energy",
        "unit": "https://qudt.org/vocab/unit/EV",
        "quantity": "https://qudt.org/vocab/quantitykind/Energy",
    },
]:
    """
    Calculates energy per atom for bulk structure.

    Args:
        bulk: Bulk ASE Atoms object.
        sigma: LJ sigma parameter.
        epsilon: LJ epsilon parameter.
        cutoff_radius: Cutoff radius for neighbor calculations.

    Returns:
        float: Energy per atom.
    """
    return get_energy(
        structure=bulk,
        sigma=sigma,
        epsilon=epsilon,
        cutoff_radius=cutoff_radius,
        per_atom=True,
    )

def get_vac_energy(
    vacancy_structure: Atoms,
    sigma: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
    epsilon: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ],
    cutoff_radius: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/ANGSTROM",
            "quantity": "https://qudt.org/vocab/quantitykind/Length",
        },
    ],
) -> Annotated[
    float,
    {
        "label": "vac_energy",
        "unit": "https://qudt.org/vocab/unit/EV",
        "quantity": "https://qudt.org/vocab/quantitykind/Energy",
    },
]:
    """
    Calculates total energy for structure with vacancy.

    Args:
        vacancy_structure: ASE Atoms object with vacancy.
        sigma: LJ sigma parameter.
        epsilon: LJ epsilon parameter.
        cutoff_radius: Cutoff radius for neighbor calculations.

    Returns:
        float: Total energy of vacancy structure.
    """
    return get_energy(
        structure=vacancy_structure,
        sigma=sigma,
        epsilon=epsilon,
        cutoff_radius=cutoff_radius,
        per_atom=False,
    )

def get_energy_difference(
    e_vac: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ],
    e_bulk: Annotated[
        float,
        {
            "unit": "https://qudt.org/vocab/unit/EV",
            "quantity": "https://qudt.org/vocab/quantitykind/Energy",
        },
    ],
    structure: Atoms,
) -> Annotated[
    float,
    {
        "label": "energy",
        "unit": "https://qudt.org/vocab/unit/EV",
        "quantity": "https://qudt.org/vocab/quantitykind/Energy",
    },
]:
    """
    Calculates vacancy formation energy.

    Args:
        e_vac: Energy of structure with vacancy.
        e_bulk: Energy per atom of bulk structure.
        structure: Structure with vacancy.

    Returns:
        float: Vacancy formation energy.
    """
    energy = e_vac - e_bulk * len(structure)
    return energy
